// Aliases map free-text integration names -> a TECH_LOGOS key.
const ALIASES: Record<string, string> = {
  "next.js": "nextdotjs",
  nextjs: "nextdotjs",
  vercel: "vercel",
  stripe: "stripe",
  "google analytics": "googleanalytics",
  zapier: "zapier",
  weglot: "weglot",
  cookieyes: "cookieyes",
  "ticket tailor": "tickettailor",
};

export function logoFor(name: string): TechLogo | null {
  const key = name.trim().toLowerCase();
  if (TECH_LOGOS[key]) return TECH_LOGOS[key];
  if (ALIASES[key]) return TECH_LOGOS[ALIASES[key]];
  // Loose match: first alias whose token appears in the name (handles
  // "CookieYes (GDPR)" style suffixes and "Weglot / i18n routing").
  for (const alias in ALIASES) {
    if (key.includes(alias)) return TECH_LOGOS[ALIASES[alias]];
  }
  return null;
}
